-- ---- Stub: SaveManager:restore -------------------------------------------
--@api-stub: SaveManager:restore
-- Pass a raw payload table (e.g. from a unit test or a remote sync) instead
-- of loading from a file -- useful for testing migration logic in isolation.
local test_payload = { schema_version = 2, player = { hp = 80, gold = 500 } }
mgr:restore(test_payload)
print("state restored from test payload")

-- ---- Stub: SaveManager:markDirty -----------------------------------------
--@api-stub: SaveManager:markDirty
-- Call this after any significant state change (level up, boss killed) so
-- the auto-save timer knows there is unsaved progress worth persisting.
mgr:markDirty()
-- the manager will now schedule an auto-save on the next update() tick

-- ---- Stub: SaveManager:isDirty -------------------------------------------
--@api-stub: SaveManager:isDirty
-- Check this before showing the "quit to menu" dialog to warn the player
-- about unsaved progress if there are pending changes.
if mgr:isDirty() then
    print("unsaved progress -- show 'Save before quitting?' dialog")
else
    print("no unsaved changes -- safe to quit")
end

