    mgr:delete("slot3")
    print("slot3 deleted")
else
    print("slot3 does not exist, nothing to delete")
end

-- ---- Stub: SaveManager:exists --------------------------------------------
--@api-stub: SaveManager:exists
-- Use this to decide whether to show "Continue" or "New Game" on the main
-- menu, and to grey out empty slots in the save-slot selection screen.
local has_save = mgr:exists("slot1")
if has_save then
    print("slot1 found -- show Continue button")
else
    print("no save in slot1 -- show New Game button")
end

-- ---- Stub: SaveManager:getSlots ------------------------------------------
--@api-stub: SaveManager:getSlots
-- Use this to build the save-slot selection screen: iterate the list and
